+func TestTranscriptWriter_PeriodicSync_SyncsAfterIntervalExpires(t *testing.T) {
+	dir := t.TempDir()
+	path := filepath.Join(dir, "transcript.jsonl")
+
+	w, err := NewTranscriptWriter(path, TranscriptHeader{
+		SessionID: "sess-sync-002",
